import axios from 'axios';

const API = axios.create({
  baseURL: 'http://localhost:5000/api',
});

// Helper to prevent crashes if a route isn't finished yet
const safeGet = async (url: string) => {
  try {
    return await API.get(url);
  } catch (error) {
    console.warn(`⚠️ Backend route ${url} not found.`);
    return { data: [] }; 
  }
};

export const AdminService = {
  // Artists (POST /api/artists)
  getAllArtists: () => safeGet('/artists'),
  getArtistById: (id: string) => API.get(`/artists/${id}`),
  
  // Artworks (GET /api/artworks/artist/:id)
  getArtworksByArtist: (artistId: string) => safeGet(`/artworks/artist/${artistId}`),
  
  // Books (GET /api/books)
  getAllBooks: () => safeGet('/books'),
  
  // Taxonomy (GET /api/taxonomy/all)
  getAllTaxonomy: () => safeGet('/taxonomy/all'),

  // THE MASTER IMPORT (POST /api/import/:type)
  // This is what you use for your Excel uploads
  importData: (type: 'artist' | 'artwork' | 'book' | 'section', file: File) => {
    const formData = new FormData();
    formData.append('file', file);
    return API.post(`/import/${type}`, formData, {
      headers: { 'Content-Type': 'multipart/form-data' }
    });
  }
};
